/* === DHC Design Language — Global Overrides === */

/* Page background */
.v-main { background-color: #0f172a !important; }

/* Navigation drawer / sidebar */
.v-navigation-drawer {
  background-color: #1e293b !important;
  border-right: 1px solid rgba(148, 163, 184, 0.3) !important;
}
.v-navigation-drawer .v-list-item-title {
  color: #cbd5f5 !important;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif !important;
  font-size: 0.85rem !important;
}
.v-navigation-drawer .v-list-item--active {
  background: rgba(34, 197, 94, 0.12) !important;
}
.v-navigation-drawer .v-list-item--active .v-list-item-title {
  color: #4ade80 !important;
}

/* App bar / header */
.v-app-bar {
  background: rgba(15, 23, 42, 0.9) !important;
  backdrop-filter: blur(10px) !important;
  -webkit-backdrop-filter: blur(10px) !important;
  border-bottom: 1px solid rgba(148, 163, 184, 0.3) !important;
}
.v-app-bar .v-toolbar-title { color: #e2e8f0 !important; }

/* Group cards — radial gradient like DHC cards */
.nrdb-ui-group {
  background: radial-gradient(circle at top left, #1e293b, #020617) !important;
  border: 1px solid rgba(148, 163, 184, 0.3) !important;
  border-radius: 12px !important;
}
.nrdb-ui-group .v-card-title,
.nrdb-ui-group .nrdb-ui-group-title {
  color: #94a3b8 !important;
  text-transform: uppercase !important;
  letter-spacing: 0.05em !important;
  font-size: 0.75rem !important;
  font-weight: 600 !important;
}

/* Primary text within groups */
.nrdb-ui-group .v-card-text { color: #e5e7eb !important; }

/* Buttons — pill shape */
.v-btn {
  border-radius: 999px !important;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif !important;
  font-weight: 500 !important;
  letter-spacing: 0.02em !important;
}

/* Switch styling */
.v-switch .v-switch__track { opacity: 0.7 !important; }

/* Text inputs — deep surface background */
.v-field {
  background-color: #020617 !important;
  border-radius: 8px !important;
}
.v-field input { color: #e5e7eb !important; }
.v-field--focused { border-color: #22c55e !important; }

/* Labels and secondary text */
.v-label { color: #9ca3af !important; }

/* Slider thumb and track */
.v-slider-thumb { color: #22c55e !important; }

/* Notification styling */
.v-snackbar__content {
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif !important;
}

/* Scrollbar styling */
::-webkit-scrollbar { width: 6px; }
::-webkit-scrollbar-track { background: #020617; }
::-webkit-scrollbar-thumb { background: #1e293b; border-radius: 3px; }
::-webkit-scrollbar-thumb:hover { background: #334155; }

/* System font globally */
body, .v-application {
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif !important;
}

