msg.method = 'POST';
msg.payload = {};
return msg;

// Fan out to check each service/device
// Output 1: MCP server check
// Output 2: Hue bridge check
// Output 3: CCU check
const mcp = { url: 'http://localhost:8000/', method: 'GET', requestTimeout: 3000 };
const hue = { url: 'http://hue-bridge/api/config', method: 'GET', requestTimeout: 3000 };
const ccu = { url: 'http://homematic-ccu/addons/xmlapi/version.cgi', method: 'GET', requestTimeout: 3000 };
return [mcp, hue, ccu];

// msg.payload is array of 3 responses [mcp, hue, ccu]
// Each has statusCode (200 = ok, or undefined/error)
const results = msg.payload || [];
const now = new Date().toLocaleTimeString('de-DE', {hour:'2-digit', minute:'2-digit', second:'2-digit'});

function check(resp, i) {
    if (resp && resp.statusCode && resp.statusCode >= 200 && resp.statusCode < 400) {
        return { status: 'online', code: resp.statusCode };
    }
    return { status: 'offline', code: resp ? resp.statusCode || 'err' : 'err' };
}

// Node-RED is always online if this flow is running
const nodered = { status: 'online' };
const mcp = check(results[0], 0);
const hue = check(results[1], 1);
const ccu = check(results[2], 2);

msg.payload = {
    timestamp: now,
    services: {
        nodered: nodered,
        mcp: mcp
    },
    devices: {
        hue: hue,
        ccu: ccu
    }
};
return msg;

const cls = msg.req.params.class;
msg.topic = `SELECT * FROM device WHERE dhc_class = '${cls}' ORDER BY name`;
return msg;

// Save HTTP req/res for later response, then fan out to CCU + Hue
flow.set('_sync_req', msg.req);
flow.set('_sync_res', msg.res);
const hueKey = global.get("hue_api_key") || env.get("HUE_API_KEY") || "";
if (!hueKey) { node.warn("HUE_API_KEY not set — Hue sync will fail"); }
return [
    {payload:'', topic:'ccu'},
    {payload:'', topic:'hue', url:'http://hue-bridge/api/' + hueKey + '/lights'}
];

const xml = msg.payload;
if (!xml || msg.statusCode !== 200) { msg.payload = []; msg.topic = 'ccu'; return msg; }
const devices = [];
const re = /<device\s+name='([^']+)'\s+ise_id='([^']+)'\s+unreach='([^']*)'/g;
let m;
const map = {
    'HM-CC-RT-DN':  {c:'Thermostat',v:'heating',  cap:'sensor,actor',t:'thermostat'},
    'HmIP-STHD':    {c:'Thermostat',v:'heating',  cap:'sensor,actor',t:'thermostat'},
    'HM-LC-Dim':    {c:'Light',     v:'electrical',cap:'actor',       t:'dimmer'},
    'HM-LC-Sw':     {c:'Switch',    v:'electrical',cap:'actor',       t:'switch'},
    'HmIP-BSM':     {c:'Switch',    v:'electrical',cap:'sensor,actor',t:'switch'},
    'HmIP-FSM':     {c:'Switch',    v:'electrical',cap:'sensor,actor',t:'switch'},
    'HM-LC-Bl':     {c:'Actor',     v:'network',   cap:'actor',       t:'shutter'},
    'HM-PB-2':      {c:'Controller',v:'network',   cap:'controller',  t:'button'},
    'HmIP-BRC2':    {c:'Controller',v:'network',   cap:'controller',  t:'button'},
    'HMIP-WRC2':    {c:'Controller',v:'network',   cap:'controller',  t:'button'},
    'HM-Sec-SC':    {c:'Sensor',    v:'network',   cap:'sensor',      t:'contact'},
    'HM-Sen-MDIR':  {c:'Sensor',    v:'network',   cap:'sensor',      t:'motion'},
    'HM-WDS100':    {c:'Sensor',    v:'network',   cap:'sensor',      t:'weather'},
    'HmIP-SWSD':    {c:'Sensor',    v:'network',   cap:'sensor',      t:'smoke'},
    'HmIP-ASIR':    {c:'Actor',     v:'network',   cap:'actor',       t:'siren'},
    'HM-ES-PMSw':   {c:'Switch',    v:'electrical',cap:'sensor,actor',t:'meter'},
    'HM-OU-CF':     {c:'Actor',     v:'network',   cap:'actor',       t:'chime'},
    'HM-SCI-3':     {c:'Sensor',    v:'network',   cap:'sensor',      t:'contact'},
};
const skip = ['VIR-','HM-RCV-50','HmIP-RCV-','HmIP-CCU3','Living'];
while ((m = re.exec(xml)) !== null) {
    const name = m[1], ise = m[2];
    if (skip.some(p => name.startsWith(p))) continue;
    const parts = name.split(' ');
    const model = parts[0] || '', serial = parts[1] || '';
    let mapped = null;
    for (const pfx of Object.keys(map)) { if (model.startsWith(pfx)) { mapped = map[pfx]; break; } }
    if (!mapped) continue;
    devices.push({name,protocol:'homematic',address:serial,dhc_class:mapped.c,design_view:mapped.v,capability:mapped.cap,type:mapped.t,model,manufacturer:'eQ-3',ccu_ise_id:ise,hue_unique_id:null});
}
msg.payload = devices; msg.topic = 'ccu'; return msg;

const lights = msg.payload;
if (!lights || typeof lights !== 'object' || msg.statusCode !== 200) { msg.payload = []; msg.topic = 'hue'; return msg; }
const mfr = {'LTG002':'Philips','LWA011':'Philips','LWE002':'Philips','SP 240':'Innr','RS 241 T':'Innr'};
const tm = {'Dimmable light':{c:'Light',t:'light'},'Color temperature light':{c:'Light',t:'light'},'Extended color light':{c:'Light',t:'light'},'On/Off plug-in unit':{c:'Socket',t:'plug'}};
const devices = [];
for (const [id, l] of Object.entries(lights)) {
    const mapped = tm[l.type] || {c:'Light',t:'light'};
    devices.push({name:'hue-'+l.name.toLowerCase().replace(/[^a-z0-9]+/g,'-'),protocol:'hue',address:id,dhc_class:mapped.c,design_view:'electrical',capability:'actor',type:mapped.t,model:l.modelid||'',manufacturer:mfr[l.modelid]||'Unknown',ccu_ise_id:null,hue_unique_id:l.uniqueid||null});
}
msg.payload = devices; msg.topic = 'hue'; return msg;

const ccu = msg.payload.ccu || [];
const hue = msg.payload.hue || [];
const all = [...ccu, ...hue];
const esc = v => v ? v.replace(/'/g,"''") : '';
const stmts = all.map(d =>
    `INSERT OR REPLACE INTO device (name,protocol,address,type,dhc_class,design_view,capability,model,manufacturer,ccu_ise_id,hue_unique_id,last_seen) VALUES ('${esc(d.name)}','${esc(d.protocol)}','${esc(d.address)}','${esc(d.type)}','${esc(d.dhc_class)}','${esc(d.design_view)}','${esc(d.capability)}','${esc(d.model)}','${esc(d.manufacturer)}',${d.ccu_ise_id?"'"+esc(d.ccu_ise_id)+"'":'NULL'},${d.hue_unique_id?"'"+esc(d.hue_unique_id)+"'":'NULL'},datetime('now'))`
);
msg.topic = stmts.join(";\n");
msg._counts = {ccu:ccu.length, hue:hue.length, total:all.length};
return msg;

// Restore HTTP req/res and build response
msg.req = flow.get('_sync_req');
msg.res = flow.get('_sync_res');
msg.payload = {status:'ok', synced: msg._counts || {ccu:0, hue:0, total:0}};
return msg;

// Read digitalhome.edge.config.cache and store keys in global context
// fs module is loaded via the node's "libs" config
const cfgPath = '/home/dhc-svc/digitalhome-edge/digitalhome.edge.config.cache';
try {
    const cfg = JSON.parse(fs.readFileSync(cfgPath, 'utf8'));
    const hueKey = (cfg.devices && cfg.devices['hue-bridge'] && cfg.devices['hue-bridge'].api_key) || '';
    global.set('hue_api_key', hueKey);
    global.set('edge_config', cfg);
    node.log('Config loaded: hue_api_key=' + (hueKey ? 'set' : 'empty'));
    return {payload: {status: 'config loaded', hue_key_set: !!hueKey}};
} catch(e) {
    node.error('Failed to load config: ' + e.message);
    return {payload: {status: 'config load failed', error: e.message}};
}
